ee:message.ee:set-payload:
%dw 2.0
output application/json
import nowUtc from modules::datetime::utils
---
{
  dateTime: nowUtc(),
  httpStatus: 201,
  status: "SUCCESS",
  message: "Customer records processed successfully.",
  correlationId: correlationId,
  data: {
    recordCount: sizeOf(payload),
    processedCount: sizeOf(payload),
    skippedCount: 0
  }
} as Object {encoding: "UTF-8", mediaType: "application/json"}
